}

/* ── Base resets ─────────────────────────────────────────────────────── */

@layer base {
  html {
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
  }

  body {
    font-family: var(--font-family-base);
    color: var(--color-foreground);
    background: var(--color-background);
    font-feature-settings: "ss01", "ss02", "cv01";
  }

  /* Accessible focus ring — uses the ring color token */
  :focus-visible {
    outline: 2px solid var(--color-ring);
    outline-offset: 2px;
  }

  /* Remove default focus for mouse users */
  :focus:not(:focus-visible) {
    outline: none;
  }

  .visually-hidden {
    position: absolute;
    width: 1px;
    height: 1px;
    padding: 0;
    margin: -1px;
    overflow: hidden;
    clip: rect(0, 0, 0, 0);
    white-space: nowrap;
    border: 0;
  }
}

/* ── Scrollbar styling ───────────────────────────────────────────────── */

@layer base {
  ::-webkit-scrollbar {
    width: 6px;
    height: 6px;
  }
  ::-webkit-scrollbar-track {
    background: transparent;
  }
  ::-webkit-scrollbar-thumb {
    background: var(--color-border);
    border-radius: var(--radius-full);
    transition: background 0.2s;
  }
  ::-webkit-scrollbar-thumb:hover {
    background: var(--color-muted);
  }
}

/* ── Theme transition ────────────────────────────────────────────────── */

@layer base {
  [data-theme] {
    transition: background-color 0.2s ease, color 0.2s ease, border-color 0.2s ease;
  }
}

/* ── Chess piece shade tokens ─────────────────────────────────────────
 * Used by Reports, ChessDistributionSection, and AnswerRenderer via
 * var(--chess-king) etc. Flip to light shades in dark mode so the
 * gradient still reads darkest=KING → lightest=PAWN relative to bg.
 */

@layer base {
  :root {
    --chess-king: #0a0a0a;
    --chess-queen: #262626;
    --chess-rook: #525252;
    --chess-bishop: #737373;
    --chess-knight: #a3a3a3;
    --chess-pawn: #d4d4d4;
  }
  [data-theme="dark"] {
    --chess-king: #f5f5f5;
    --chess-queen: #d4d4d4;
    --chess-rook: #a3a3a3;
    --chess-bishop: #737373;
    --chess-knight: #525252;
    --chess-pawn: #2a2a2a;
  }
}

/* ── Transitions ─────────────────────────────────────────────────────── */

@layer utilities {
  .transition-sidebar {
    transition: width 200ms ease-in-out, padding 200ms ease-in-out;
  }
}

